    14→  ERROR = 'error',
    15→}
    16→
    17→export type TransactionType = 'CREDIT' | 'RESCUE' | 'EXPIRED' | 'REFUNDED';
    18→
    19→export const TYPE_LABELS: Record<TransactionType, string> = {
    20→  CREDIT: 'Ganhos',
    21→  RESCUE: 'Usados',
    22→  EXPIRED: 'Expirados',
    23→  REFUNDED: 'Reembolsados',
